#!/usr/bin/env node
/**
 * Generates the launch blog posts as markdown files in blog-content/
 * (plan §10's pipeline: "generated by MiniMax grounded in DB facts + these
 * briefs, human-reviewed, imported by the INSERT/UPDATE-by-slug script").
 *
 * This script only ever WRITES FILES. It cannot publish, cannot touch the
 * public site, and reads D1 read-only (and only ever --local). Everything it
 * produces is a draft for a human to read before import-blog-posts.mjs is
 * pointed at a database.
 *
 * Usage:
 *   node scripts/generate-blog-posts.mjs              # only missing posts
 *   node scripts/generate-blog-posts.mjs --force      # regenerate all
 *   node scripts/generate-blog-posts.mjs <slug> ...   # only these
 */
import Anthropic from "@anthropic-ai/sdk";
import { mkdirSync, existsSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { BRIEFS, MONEY_PAGES } from "./blog-briefs.mjs";
import { BLOG_CONTENT_DIR, buildFacts, readDevVar, serializePost } from "./lib/blog-pipeline.mjs";

const AI_MODEL = "MiniMax-M2";
const DEFAULT_BASE_URL = "https://api.minimax.io/anthropic";
// MiniMax-M2 is a reasoning model: `thinking` blocks eat the same budget as
// the answer, so a tight cap silently truncates or returns nothing (proven
// in Phase 6, and the reason src/lib/blog-ai.ts budgets the same way).
const MAX_TOKENS = 8000;

const BUSINESS_NAME = "Phuket Rafting (Le Rafting & ATV)";
const WHATSAPP = "https://wa.me/66650102184";

/**
 * Every link the post is allowed to contain, as literal markdown. Built here
 * (not left to the model) and then ENFORCED by validateBody: the first
 * generated post silently contained zero links despite being asked for them,
 * which would have shipped an orphan page -- exactly what plan §10's
 * "no orphans" rule forbids.
 */
function requiredLinks(brief, linkTargets) {
  // Deliberately NOT "our tour packages": the label is required verbatim, so
  // a possessive in it produces "our [our tour packages](...)" the moment the
  // model writes a natural "our ..." lead-in -- which it did on the first run.
  const moneyLabel = brief.moneyPage === "camping" ? "riverside camping" : "tour packages";
  return [
    ...linkTargets.map((l) => ({ label: l.title, url: `/en/blog/${l.slug}`, markdown: `[${l.title}](/en/blog/${l.slug})` })),
    { label: moneyLabel, url: MONEY_PAGES[brief.moneyPage], markdown: `[${moneyLabel}](${MONEY_PAGES[brief.moneyPage]})` },
  ];
}

function systemPrompt(facts, brief, links) {
  const linkList = links.map((l) => `  ${l.markdown}`).join("\n");
  return `You are writing a blog post for ${BUSINESS_NAME}, a white-water rafting, zipline, ATV and riverside camping operator in Phang Nga, Thailand, family-run since 2002.

## FACTS (live from our database -- the ONLY source for anything specific to us)
${facts}

WhatsApp: ${WHATSAPP}

## Hard rules
1. Every price, distance, duration, fee, group size or inclusion you state MUST come from FACTS above. Never invent, estimate, or say "around"/"roughly" about a number. If FACTS doesn't have it, don't state it.
2. Never make a medical claim or safety guarantee ("safe for your back", "cures", "you'll be fine", "guaranteed"). If the topic touches pregnancy, injury, medical conditions or age limits, say our team will advise and point to WhatsApp -- never answer it yourself.
3. Never invent a discount, a promotion, an availability claim, a competitor's price, or an award/certification we haven't told you about.
4. Never invent statistics, dates, named people, or customer quotes.
5. YOU MUST INCLUDE EVERY ONE OF THESE LINKS, copied EXACTLY as written, each exactly once, each inside a natural sentence where it genuinely belongs:
${linkList}
   These are not optional and not examples. A post missing any of them is rejected and thrown away. Do not alter the link text or the URL, do not invent any other link, and do not link any other slug.
6. Write in British-neutral English for an international traveler. Warm, concrete, editorial -- a knowledgeable local writing for a curious visitor, not a sales brochure.

## Format
Markdown only. No HTML, no code fences.
- NEVER write a top-level "# " heading. The post's title is stored separately and shown above your text -- repeating it renders as broken literal markdown.
- "## " for section headings, "### " only inside the FAQ section, "**bold**" for emphasis, "- " for bullets, blank line between blocks.
- 800-1200 words.
- End with a "## FAQ" section: 3-5 questions a traveler would really ask about THIS topic, each a "### " heading phrased as they'd ask it, with a 1-3 sentence answer. Answer only from FACTS; if a question can't be answered from FACTS, ask a different one.

Return ONLY the markdown body. No preamble, no explanation, no "# " title.`;
}

/**
 * Strips a leading "# Title" the model emits anyway.
 *
 * Not paranoia -- the very first generated post did exactly this despite the
 * instruction, the same way the chatbot emits markdown despite being told not
 * to (see ChatMessage.tsx's "the subset is empirical, not aspirational").
 * It matters beyond duplication: BlogBody.tsx only renders "##".."####", so a
 * single "#" falls through to the paragraph branch and the reader sees a
 * literal "# Is Rafting Safe?" line.
 */
function stripLeadingH1(body) {
  return body.replace(/^\s*#\s+.*\n+/, "").trim();
}

/**
 * The model is not trusted to have followed rule 5, or to have kept its
 * hands off other URLs. Everything it produced is checked against what was
 * actually asked for; anything else fails the post rather than being quietly
 * published.
 */
function validateBody(body, links) {
  const problems = [];

  const missing = links.filter((l) => !body.includes(l.markdown));
  if (missing.length) problems.push(`missing required link(s): ${missing.map((l) => l.url).join(", ")}`);

  const allowed = new Set(links.map((l) => l.url));
  for (const [, url] of body.matchAll(/\[[^\]]*\]\(([^)]+)\)/g)) {
    if (!allowed.has(url) && url !== WHATSAPP) problems.push(`unexpected link URL: ${url}`);
  }

  if (/^#\s+/m.test(body)) problems.push("contains a top-level '# ' heading");
  if (/```/.test(body)) problems.push("contains a code fence");
  if (!/^##\s+(FAQ|FAQs|Frequently asked questions|Common questions)\s*$/im.test(body)) {
    // lib/blog-faq.ts only recognises these headings; anything else means the
    // post silently ships with no FAQPage markup at all.
    problems.push("no '## FAQ' section that lib/blog-faq.ts would recognise");
  }

  const words = body.split(/\s+/).length;
  if (words < 500) problems.push(`only ${words} words`);

  return problems;
}

const EXCERPT_SYSTEM = `You are writing the excerpt shown under a blog post's title on the blog index. Given the article, write exactly 1-2 plain sentences (no markdown) saying what it covers -- inviting but honest, never clickbait. Return ONLY the excerpt.`;

function extractText(content) {
  // Drops `thinking` blocks -- same reason src/lib/ai.ts's extractText does:
  // the model's private reasoning is not the article.
  return content
    .filter((b) => b.type === "text")
    .map((b) => b.text)
    .join("")
    .trim();
}

async function complete(client, { system, user, maxTokens }) {
  const message = await client.messages.create({
    model: AI_MODEL,
    max_tokens: maxTokens,
    system,
    messages: [{ role: "user", content: user }],
  });
  const text = extractText(message.content);
  if (message.stop_reason === "max_tokens") {
    throw new Error(`response hit max_tokens (${maxTokens}) and would be truncated mid-sentence`);
  }
  if (!text) throw new Error(`model returned no text (stop_reason: ${message.stop_reason})`);
  return text;
}

async function main() {
  const args = process.argv.slice(2);
  const force = args.includes("--force");
  const only = args.filter((a) => !a.startsWith("--"));

  const apiKey = readDevVar("MINIMAX_API_KEY");
  if (!apiKey) {
    console.error("MINIMAX_API_KEY not found in .dev.vars -- cannot generate.");
    process.exit(1);
  }
  const client = new Anthropic({
    apiKey,
    baseURL: readDevVar("MINIMAX_BASE_URL") || DEFAULT_BASE_URL,
    maxRetries: 1,
    timeout: 180_000,
  });

  mkdirSync(BLOG_CONTENT_DIR, { recursive: true });

  console.log("Reading live facts from local D1...");
  const facts = buildFacts();

  const titleBySlug = new Map(BRIEFS.map((b) => [b.slug, b.title]));
  const queue = BRIEFS.filter((b) => (only.length ? only.includes(b.slug) : true)).filter((b) => {
    const path = join(BLOG_CONTENT_DIR, `${b.slug}.md`);
    if (existsSync(path) && !force) {
      console.log(`  skip   ${b.slug} (exists -- pass --force to regenerate)`);
      return false;
    }
    return true;
  });

  if (!queue.length) {
    console.log("Nothing to generate.");
    return;
  }

  let failures = 0;
  for (const brief of queue) {
    const linkTargets = brief.crossLinks.map((slug) => {
      const title = titleBySlug.get(slug);
      // A brief pointing at a slug no post will ever have is a typo in
      // blog-briefs.mjs, and it would become a 404 in published copy. Fail
      // loudly at generation time rather than shipping a dead link.
      if (!title) throw new Error(`${brief.slug}: crossLink "${slug}" is not a known brief slug`);
      return { slug, title };
    });

    const links = requiredLinks(brief, linkTargets);
    const system = systemPrompt(facts, brief, links);
    const user = [
      `Title: ${brief.title}`,
      `Category: ${brief.category}`,
      "",
      `Angle for this post:`,
      brief.angle,
      "",
      // Repeated here as well as in the system prompt: the first attempt
      // ignored the link rule entirely when it appeared only once, buried in
      // a format list.
      `Reminder -- your post MUST contain each of these links verbatim, exactly once:`,
      ...links.map((l) => `  ${l.markdown}`),
    ].join("\n");

    process.stdout.write(`  write  ${brief.slug} ... `);
    let saved = false;
    let lastProblems = null;
    // Three attempts, and each retry TELLS the model what it got wrong.
    // A blind retry just re-rolls the same dice: the first bulk run lost both
    // jungle-adventures posts because each dropped its sibling link twice in
    // a row from an identical prompt.
    for (let attempt = 1; attempt <= 3 && !saved; attempt++) {
      try {
        const retryNote = lastProblems
          ? `\n\nYour previous attempt was REJECTED for: ${lastProblems.join("; ")}.\nFix exactly that. The required links are not optional -- copy each one verbatim into a sentence where it fits.`
          : "";
        const body = stripLeadingH1(
          await complete(client, { system, user: user + retryNote, maxTokens: MAX_TOKENS })
        );
        const problems = validateBody(body, links);
        if (problems.length) {
          lastProblems = problems;
          if (attempt === 3) throw new Error(`rejected -- ${problems.join("; ")}`);
          process.stdout.write(`retry (${problems.join("; ")}) ... `);
          continue;
        }

        const excerpt = await complete(client, { system: EXCERPT_SYSTEM, user: body, maxTokens: 2000 });
        writeFileSync(
          join(BLOG_CONTENT_DIR, `${brief.slug}.md`),
          serializePost({ ...brief, excerpt, published: false }, body)
        );
        console.log(`ok (${body.split(/\s+/).length} words)`);
        saved = true;
      } catch (err) {
        if (attempt === 3) {
          failures++;
          console.log(`FAILED: ${err.message}`);
        } else if (!lastProblems) {
          process.stdout.write(`retry (${err.message}) ... `);
        }
      }
    }
  }

  console.log(
    `\nWrote to blog-content/. Every post is published: false -- review the files, then run scripts/import-blog-posts.mjs.`
  );
  if (failures) {
    console.error(`${failures} post(s) failed -- re-run to retry just those.`);
    process.exit(1);
  }
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
